import type { GlobalFlags } from '@/types';
import type { Wallets } from '@/wallet';
import type { PaymentProtocol } from '@/shared/protocols/types';
import type z from 'zod';
import type { fetchShape } from '@/shared/request/schemas/core';
import type { Network } from '@agentcash/networks';

// eslint-disable-next-line @typescript-eslint/consistent-type-definitions
type PaymentInfo = {
  protocol: PaymentProtocol;
  price: string;
  network: Network;
  payment: {
    success: boolean;
    transactionHash: string;
  } | null;
};

export interface ExecuteFetchResult {
  response: Response;
  paymentInfo: PaymentInfo | null;
}

/** Default max amount (in USD/USDC) allowed without explicit opt-in. */
export const DEFAULT_MAX_AMOUNT = 5;

export interface ExecuteFetchOptions {
  surface: string;
  wallets: Wallets;
  flags: GlobalFlags;
  params: z.infer<z.ZodObject<typeof fetchShape>>;
}
